import{_ as e,o,c as r,ag as a}from"./chunks/framework.OsDJF_Ea.js";const n="/docs/modules/modal-resonator.png",m=JSON.parse('{"title":"Modal Resonator","description":"","frontmatter":{},"headers":[],"relativePath":"modules/modal-resonator.md","filePath":"modules/modal-resonator.md"}'),s={name:"modules/modal-resonator.md"};function d(i,t,l,p,u,h){return o(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="modal-resonator" tabindex="-1">Modal Resonator <a class="header-anchor" href="#modal-resonator" aria-label="Permalink to &quot;Modal Resonator&quot;">​</a></h1><p><strong>Category:</strong> Effects</p><p>16 parallel SVF bandpass resonators that ring at configured frequencies when excited by any audio input. Built-in presets for common resonant objects, plus profile morphing between two snapshots.</p><img src="'+n+'" alt="modal-resonator module"><h2 id="inputs" tabindex="-1">Inputs <a class="header-anchor" href="#inputs" aria-label="Permalink to &quot;Inputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>inL</strong> (audio)</td><td>Left audio input (excitation signal: piezo, noise, impulse).</td></tr><tr><td><strong>inR</strong> (audio)</td><td>Right audio input.</td></tr><tr><td><strong>feedback</strong></td><td>Resonance decay time 0-1. Higher = longer ringing.</td></tr><tr><td><strong>depth</strong></td><td>High-frequency emphasis (brightness) 0-1. Controls amplitude rolloff of upper partials.</td></tr><tr><td><strong>freqMod</strong></td><td>Pitch shift all bands. 0.5 = no shift, 0 = -24 semitones, 1 = +24 semitones.</td></tr><tr><td><strong>mix</strong></td><td>Dry/wet mix 0-1. 0 = dry only, 1 = resonator only.</td></tr><tr><td><strong>pan</strong></td><td>Morph between profile A and B. 0 = A, 1 = B.</td></tr><tr><td><strong>trigger</strong></td><td>Trigger fires internal impulse to excite the resonator (no external noise needed). Also fires automatically when SpectralCapture loads a new profile.</td></tr><tr><td><strong>noteCV</strong></td><td>Note CV input (0-1 = MIDI notes 0-127). Transposes all bands chromatically relative to the captured fundamental. Connect MIDIIn noteCV to play the resonator like an instrument.</td></tr></tbody></table><h2 id="outputs" tabindex="-1">Outputs <a class="header-anchor" href="#outputs" aria-label="Permalink to &quot;Outputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>outL</strong> (audio)</td><td>Left resonator output.</td></tr><tr><td><strong>outR</strong> (audio)</td><td>Right resonator output.</td></tr><tr><td><strong>env_follow</strong></td><td>Envelope follower tracking resonator output level 0-1.</td></tr></tbody></table><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><p>Trigger input fires a short internal noise impulse to excite the resonator - no external Noise module needed. Connect MIDIIn noteCV to play the captured spectral character chromatically. Use morph to blend between two captured profiles.</p><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2>',11)])])}const g=e(s,[["render",d]]);export{m as __pageData,g as default};
